var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"알콩달콜 블링블링 그레모리 바?","JPN":"ラブラブキラキラグレモリーのバー？","ENG":"\\"Happy Daze Magic Lounge Gremory's Bar?\\"","TWN":"七彩炫目的葛茉莉酒吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_RELEASED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"네. 그레모리라는 이름을 쓰는 바는 이 가게 하나뿐입니다.","JPN":"はい。グレモリーを名前に使っているお店はここしかありません。","ENG":"Yes. This is the only bar around here that's named Gremory.","TWN":"對，這裡叫葛茉莉的酒吧，就只有這麼一間。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_RELEASED","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"찾으시던 데가 여기 아닌가요?","JPN":"探していたお店はここじゃないですか？","ENG":"Isn't it what you're looking for?","TWN":"你要找的地方應該就是這裡吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOSTAGE_NPC_POSIONRAT_RELEASED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하, 하지만 음침하지 않고 입구부터 알록달록하지 않나요?","JPN":"で、でも薄暗い感じもないし、入り口も鮮やかです。","ENG":"B-but it doesn't look gloomy at all... The entrance looks too colorful.","TWN":"可…可是它一點也不灰暗，從大門口就很色彩繽紛欸？"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"사악한 느낌도 전혀 없고…….","JPN":"邪悪な雰囲気も感じられませんし……","ENG":"It doesn't look evil, either...","TWN":"一點都沒有邪惡的感覺……"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"예? 그러면 무슨 문제라도 되는 건가요?","JPN":"え？　それだと何か問題でもあるんですか？","ENG":"Huh? Is that a problem?","TWN":"嗯？這有什麼問題嗎？"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 아무것도 아니에요! 직접 안내해 주셔서 감사합니다!","JPN":"な、なんでもありません！　ここまで案内してくれてありがとうございます！","ENG":"N-never mind. Thank you for showing me the way here.","TWN":"喔，沒有啦！謝謝你替我帶路！"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"감사는요. 제 목숨을 구해주신 은인이신데 이 정돈 당연히 해 드려야죠.","JPN":"いえいえ。命を救ってくれた恩人なので、このくらい当然です。","ENG":"You're welcome. You saved my life! It's the least I can do.","TWN":"沒什麼好謝的，你可是我的救命恩人，這點小忙是我應該幫的！"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOSTAGE_NPC_POSIONRAT_RELEASED","text":{"KOREA":"그럼 전 이만…","JPN":"それでは私はこれで……","ENG":"Goodbye, then.","TWN":"那我就先走一步…"},"stage":{"bg":"BAR_ENTRY_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여기가 악마가 있다는 술집…….","JPN":"ここが悪魔がいると言われている酒場……","ENG":"So, this is the devilish bar...","TWN":"這裡面有魔鬼嗎……"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"입구부터 제가 생각하던 분위기와는 좀 다르네요.","JPN":"入口からすでに思っていた雰囲気とは少し違いますね。","ENG":"The entrance looks totally different from what I expected.","TWN":"怎麼從大門感覺就和我的認知不太一樣？"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 펜듈럼은 이곳에서도 여전히 반응하고 있어요.","JPN":"でもペンデュラムはここでも相変わらず反応しています。","ENG":"But my pendulum is reacting to this place as well.","TWN":"不過鐘擺對這裡也有反應！"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇다는 건… 멀리서도 반응할 정도로 강력한 악마라는 뜻이겠죠.","JPN":"ということは……遠くからでも反応するような強力な悪魔ということでしょう。","ENG":"That means... the devil is so powerful that its presence can be detected even from far away.","TWN":"意思就是…這裡的魔鬼強到，在很遠的地方也感應得到吧！"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"……정말 저 혼자서도 괜찮은 거겠죠?","JPN":"……本当に私一人でも大丈夫でしょうか？","ENG":"... I can do this alone, right?","TWN":"……我自己一個人真的可以嗎？"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"지상에 올라온 악마들은 교활해서 쉽게 정체를 드러내지 않는다고 하던데…….","JPN":"地上にでて来た悪魔たちは狡猾で簡単には正体を現さないそうですが……","ENG":"I was told devils on earth are cunning and rarely expose themselves...","TWN":"我聽說地上的魔鬼都很狡猾，不會輕易露出真面目……"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"악마를 직접 본 적도 없는 제가 과연 악마를 찾아낼 수 있을지 걱정이네요.","JPN":"悪魔を直接見たこともない私が、果たして悪魔を見つけられるか心配です。","ENG":"I've never seen a devil before. I don't know if I can even find one.","TWN":"我又沒親眼看過魔鬼，真的有辦法揪出魔鬼來嗎？"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"분명 쉽지 않겠지만… 시간은 충분하니 차근차근 찾아보면 되겠죠!","JPN":"きっと簡単ではないと思いますが……時間は十分あるので、慎重に探していけば大丈夫でしょう！","ENG":"It won't be easy, but I've got plenty of time. I'll take one step at a time!","TWN":"感覺就是個大難題…反正時間很充裕，我就慢慢地找吧！"},"stage":{"bg":"BAR_ENTRY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"실례합니다.","JPN":"ごめんください。","ENG":"Excuse me.","TWN":"不好意思～"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"어서 오거라, 손님아!","JPN":"よくぞ来た、客よ。","ENG":"Welcome to my palace, customer!","TWN":"你好，歡迎光臨！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"빛이여! 악을 정화하소서!","JPN":"光よ！　悪を浄化したまえ！","ENG":"Oh, Light! Purge the evil!","TWN":"真光來驅除這裡的惡吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ENERGY_BIG"},{"id":"L37_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"으갸아아악!","JPN":"ふんぎゃあああぁっ！","ENG":"Waaah!","TWN":"哎呀哎呀哎呀！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_DAMAGE_DIE_03"},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"휴, 생각보다 찾기 쉬웠네요. 애써 조사할 필요도 없었군요.","JPN":"ふう、思ったよりすぐに見つかりましたね。\\nわざわざ調査する必要もありませんでした。","ENG":"Whew, that was easier than I thought. I didn't even have to look.","TWN":"呼～得來全不費工夫呢！根本不需要找得那麼辛苦嘛～"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이걸로 성무는 무사히 완수… 응?","JPN":"これで聖務は無事完遂……ん？","ENG":"With that, my holy mission is accomplished—mm?","TWN":"那我應該算是任務完成…嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"으으으…","JPN":"ううぅ……","ENG":"Ugh...","TWN":"呃呃呃…"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아직도 살아 있다니!","JPN":"まだ生きてるなんて！","ENG":"It's still alive!","TWN":"怎麼還沒死！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이럴 땐 어떻게 해야 하죠? 확인사살?","JPN":"こういう時はどうすればいいでしょう？　もう一度とどめ？","ENG":"What do I do now? Shoot again?","TWN":"這時候該怎麼辦？再補她幾槍嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"히이익!","JPN":"ひいいーっ！","ENG":"Heeek!","TWN":"嗚嗚嗚！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아앗! 거기 서세요, 이 악마!","JPN":"ああっ！　待ちなさい、この悪魔！","ENG":"Ah! Stop right there, you devil!","TWN":"喂喂！魔鬼，站住別動！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그, 그레모리! 도와줘어!","JPN":"グ、グレモリー！　助けてぇ！","ENG":"G-Gremory! Help me!","TWN":"葛…葛茉莉！快來幫我！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"으음… 시끄러어…","JPN":"うぅん……うるさい……","ENG":"Mm... So loud...","TWN":"什麼…好吵喔…"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"지금 취해서 잠꼬대할 때가 아니다! 웬 인간 여자가 날 퇴치하려 한단 말이니라!","JPN":"酔って寝言言ってる場合ではないぞ！\\n人間の女が吾輩を退治しようとしておる！","ENG":"Wake up and get sober, quick! Some human girl is trying to exorcise me!","TWN":"現在不是發酒瘋的時候！有個莫名其妙的人類女生想打死我啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"때리는 게 아니에요! 신성한 정화의식이라고요! 순순히 지옥으로 돌아가 주시죠!","JPN":"ただ叩いているわけではありません！　神聖なる浄化儀式です！　大人しく地獄に帰ってください！","ENG":"I'm not beating you! This is a sacred purging ritual! Please go back to Hell when I ask nicely!","TWN":"我沒有打你！這是神聖的淨化儀式！你乖乖地回到地獄去吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"흐엑! 쫓아왔다!","JPN":"ほええ！　おいかけて来たぞ！","ENG":"Heek! She's here!","TWN":"嗚嗚！追過來了啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"해, 해치지 마세요. 사탕 드릴게요.","JPN":"い、いじめないでください。このキャンディ、全部あげるから！","ENG":"P-please don't hurt me. I'll give you my candy.","TWN":"別打我，我給你糖果！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"필요 없어요!","JPN":"いりません！","ENG":"No, thanks!","TWN":"不稀罕！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"우와아아아!","JPN":"ふえええええ！","ENG":"Waaah!","TWN":"嗚哇哇！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"으… 시끄럽다니까…","JPN":"もう……うるさいってば……","ENG":"Aww... I said, loud...","TWN":"唔…你真的好吵…"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_NEGOTIATE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"앗?","JPN":"あっ？","ENG":"Ah?","TWN":"嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"드르렁~ 쿠울…","JPN":"ぐう～ぐう～スヤァ……","ENG":"Zzz... Whew...","TWN":"呼嚕嚕～呼嚕…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어, 어라? 어째서 졸음이…?","JPN":"あ、あれ？　なぜか眠気が……？","ENG":"E-err... Why am I sleepy all of a sudden?","TWN":"嗯？突然覺得好睏…？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음…","JPN":"ううん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"여긴…?","JPN":"ここは……？","ENG":"Where am I?","TWN":"這裡是…？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"많이 피곤했던 모양이네. 면접 보는 도중에 잠들어 버리다니 말이야.","JPN":"ずいぶんお疲れだったみたいね。面接の途中で眠ってしまうなんて。","ENG":"You must have been tired. You fell asleep during your interview.","TWN":"你是不是太累了？剛剛面試到一半就睡著了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗? 제가 졸았나요? 죄송해요!","JPN":"あっ、居眠りしちゃってましたか？　すみません！","ENG":"Ah, did I? I'm sorry!","TWN":"蛤？我睡著了嗎？真是不好意思！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"이력서는 잘 봤어.","JPN":"履歴書は確認したわ。","ENG":"I read your resume.","TWN":"我看過你的履歷表了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"샤레이드 출신이라… 거긴 콧대 높은 졸부들만 남아 있는 줄 알았는데…","JPN":"シャレード出身ね……あそこは成金しか住んでないと思ってたのに……","ENG":"You're from Charade, huh? I thought only arrogant upstarts lived there now.","TWN":"上面說你來自查雷德…據我所知，那裡應該都是些眼睛長在頭頂上的的暴發戶吧…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"그런 곳에서 귀하게 자란 아가씨가 바텐더 일을 하려고 이렇게 험한 도시까지 내려오다니, 오래 살고 볼 일인걸?","JPN":"そんな所で育ったお嬢様が、\\nバーテンダーの仕事をするためにこんな物騒な都市まで来るなんて、\\n長生きしてみるものね。","ENG":"A girl from a rich town comes all the way to this sinful city to work as a bartender? You live and learn, I guess.","TWN":"你一個嬌生慣養的千金大小姐，竟然為了想當調酒師，跑到這麼危險的都市來，還真是稀奇呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 실은 집안에서도 걱정을 많이 했거든요. 저 같은 애가 퇴마… 가 아니라, 술집에서 일한다고요.","JPN":"はい、実は家族もとても心配していたんです。\\n私みたいな子が退魔……じゃなくて、酒場で働きたがるなんてって。","ENG":"Oh, actually, my family was worried about the same. They didn't want me to become an exor—a bartender.","TWN":"喔，其實家裡知道我要當驅魔…不是，是在酒吧上班的時候也很擔心我呢！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그래도 제가 남들보다 좀 빨리 배우고 익히는 타입이라 재능을 인정받았어요!","JPN":"でも私は周りより飲み込みが早いタイプなので、才能を認められたんです！","ENG":"But I'm a quick learner. I finished the course quicker than the others!","TWN":"不過家人也都認同我的學習能力比別人好！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"그래? 잘됐네. 여기도 마침 그런 인재가 필요하던 참이었거든.","JPN":"そうなの？　よかったわ。\\nこの店にもちょうどそういう人材が必要だったところなのよ。","ENG":"Did you? Good, I could use someone like you.","TWN":"是嗎？那太好啦，我們店裡正好需要這種人才！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"난 여기 가게 주인. 편하게 주인님이라고 불러.","JPN":"アタシはここの店主。アタシのことは気軽にご主人様と呼んでね。","ENG":"I own this bar. You can call me Mistress.","TWN":"我是這家店的主人，你就稱呼為我主人吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"알겠습니다, 주인님!","JPN":"わかりました、ご主人様！","ENG":"Yes, Mistress!","TWN":"是，主人！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_NULL_QM","text":{"KOREA":"우와, 순진하기도 하지.","JPN":"あらぁ、なんて純粋な子かしら。","ENG":"Wow, you're so trusting, aren't you?","TWN":"哇～怎麼這麼單純～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"주인님은 농담이야. 편하게 그레모리 씨라고 부르면 돼.","JPN":"ご主人様は冗談よ。グレモリーさんでいいわ。","ENG":"You don't have to call me Mistress. I was just messing with you. Call me Gremory.","TWN":"主人是開玩笑的，你叫我葛茉莉就好。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나랑 술 한 잔하고 난 뒤엔 언니라고 불러도 좋고.","JPN":"飲み友になってくれるならお姉ちゃんでもいいし。","ENG":"You can call me sis, too, once we've had a drink together.","TWN":"和我喝過酒後，也可以叫我茉莉姊。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하…","JPN":"あはは……","ENG":"Aha...","TWN":"哈…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그건 그렇고…","JPN":"それにしても……","ENG":"By the way...","TWN":"先不說這個…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"니콜 양은 준비성이 철저한걸? 총을 가지고 다니는 바텐더는 흔치 않거든.","JPN":"ニコルちゃんって準備が良いわね。\\n銃を持ち歩くバーテンダーなんて滅多にいないから。","ENG":"Nicole, you came prepared, didn't you? Not many bartenders carry a gun, you know.","TWN":"妮可，你是一個準備很周全的人嗎？很少看到有調酒師會隨身攜帶槍呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 이건 퇴마… 아니, 호신용으로 가지고 있어요.","JPN":"あ、これは退魔……ではなくて、護身用に持っています。","ENG":"Ah, this is for exor—self-defense purposes.","TWN":"喔～這是驅魔…不是，是我拿來防身的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"집안에서 내려오는 신성한 가보 같은 건데, 어쩌다 보니 제가 맡게 됐거든요.","JPN":"うちの家に代々伝わる神聖な家宝みたいなものなんですが、\\nたまたま私が預かることになったんです。","ENG":"It's my family's sacred heirloom, and I was put in charge of it somehow.","TWN":"好像是珍貴的傳家寶吧？不知道為什麼會落到我手上。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음, 그러니?","JPN":"へえ、なるほどね。","ENG":"Hmm, I see.","TWN":"嗯嗯，是這樣嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하하… 아무래도 이런 가게에서 일하려면 두고 오는 편이 좋겠죠?","JPN":"はは……やっぱりこういうお店で働くためには置いてきたほうがいいでしょうか？","ENG":"Hah hah... I should leave it home if I work here, right?","TWN":"哈哈…帶把槍在店裡上班很怪吧？是不是不帶比較好？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"상관없어. 가게에서 소란이나 피우는 불청객은 나도 질색이니까.","JPN":"構わないわ。店で騒ぎ立てる迷惑な客はアタシも苦手だから。","ENG":"I don't care. I don't want drunken rowdies in my bar, either.","TWN":"我無所謂，我自己也很討厭那些在店裡鬧事的不速之客。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"실수로 쏴 버려도 뒤처리는 내가 잘해 줄 테니 걱정 마.","JPN":"うっかり撃っちゃっても、後始末はアタシがやってあげるから心配しないで。","ENG":"Even if you shoot them by accident, I can take care of them. Don't worry.","TWN":"就算你真的不小心擦槍走火，我也會善後的，別擔心～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에?! 도시에선 불청객을 그렇게까지 대하나요?","JPN":"ええっ！？　都会では迷惑なお客様にそこまでしていいんですか？","ENG":"Pardon? Is it okay to do that to unwelcome customers in the city?","TWN":"蛤？！都市都是這樣對待不速之客的嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"농담이야.","JPN":"なんてね。","ENG":"I was just joking.","TWN":"開玩笑的啦～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"역시 그렇죠? 깜짝 놀랐어요.","JPN":"やっぱりそうですよね？　びっくりしました。","ENG":"I know, right? You almost had me fooled.","TWN":"我就知道！嚇我一跳！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐, 뒤처리를 해주겠다는 부분은 진심. 출근할 땐 총도 가져와도 돼.","JPN":"まあ、後始末をしてあげるってのは本当よ。出勤する時に銃の持参もオッケー。","ENG":"Well, I'm serious about taking care of your mess. You can bring your gun to work.","TWN":"也不完全是開玩笑啦，善後的事我是認真的。你上班的時候可以帶槍，完全沒問題！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼 어떤 부분이 농담이었던 거죠?!","JPN":"では、どこが冗談だったんでしょうか！？","ENG":"Then, which part was a joke?","TWN":"那哪句話才句話開玩笑？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"난 오히려 소란 피우는 불청객을 좋아하거든.","JPN":"アタシはむしろ、騒ぎ立てる客が好きなのよ。","ENG":"That I don't want drunken rowdies. Because I like them.","TWN":"我反而很喜歡鬧事的不速之客呢～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(뭔가 이상해요. 이 분은 책에서 봤던 <color=#ffd34c>256가지 유형의 직장상사</color> 중에 하나도 맞는 게 없어요.)","JPN":"(何かおかしいです。この方は本で読んだ<color=#ffd34c>256タイプの職場の上司</color>に一つも当てはまりません。)","ENG":"(Something's off. She doesn't fit any of the <color=#ffd34c>256 types of bosses</color> I've read about.)","TWN":"(好奇怪，她怎麼和我在書上看到的<color=#ffd34c>256種類型的主管</color>都不一樣？)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자, 그럼 면접도 끝났겠다. 이제 슬슬 계약서를 써볼까?","JPN":"さて、面接も終わったし、そろそろ契約書を書きましょうか。","ENG":"Okay, then your interview is over. Now, are you ready to sign your contract?","TWN":"那面試就進行到這裡，來簽約吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"벌써요? 고작 잡담 몇 마디 나눈 게 전분데요?","JPN":"えっ、もういいんですか？　まだ雑談しかしていないような気がしますが。","ENG":"Already? You didn't even ask me any questions.","TWN":"這麼快？就這樣閒聊幾句就面試完啦？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그걸로 충분해. 사람의 본질은 말 몇 마디에서 드러나는 법이니까.","JPN":"それで十分よ。人の本質はちょっとした会話に表れるものだから。","ENG":"I don't have to. I can tell who people are just by exchanging a few words with them.","TWN":"這樣就夠啦，人的本性只要幾句話就可以看出來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저는 바텐더 면접이니 당연히 바텐딩 기술을 시험하실 거라고 생각했어요.","JPN":"バーテンダーの面接だから、当然バーテンディングの技術を試されると思っていました。","ENG":"Since I came here for a bartender job, I thought you'd want to see my bartending skills.","TWN":"我還以為應徵調酒師，應該會需要考一下調酒技術。　"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그런 건 차차 배워 나가면 될 문제야. 바텐더에게 중요한 건 상대방을 대하는 태도와 마음가짐이거든.","JPN":"そういうのは徐々に学んでいけばいいの。\\nバーテンダーにとって重要なのは、相手に対する態度と心構えなのよ。","ENG":"You can learn them as you go. What's more important is how sincere you are to others as a bartender.","TWN":"技術是可以學的，這不是問題。但調酒師最重要的，是應對客人的心態。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그리고 그런 마음가짐은 누가 가르친다고 쉽게 변하는 게 아니지.","JPN":"そして、そういう心構えは誰かに教わったからって簡単に変わるものじゃない。","ENG":"No one can really teach you that.","TWN":"而心態是無法透過教導就輕易改變的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그런 면에서 니콜 양은 합격이야.","JPN":"そういう面で、ニコルちゃんは合格よ。","ENG":"In that sense, you meet my standards, Nicole.","TWN":"從這一點來看的話，妮可是合格的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"와아, 감사합니다!","JPN":"わあ、ありがとうございます！","ENG":"Wow, thank you!","TWN":"哇～謝謝！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"사인은 여기에다 하면 되는 건가요?","JPN":"サインはここにすればいいんですか？","ENG":"Okay, should I sign here?","TWN":"簽名是簽在這裡嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래, 거기. 그쪽에도… 옳지.","JPN":"そう、そこよ。そっちにも……いいわ。","ENG":"Yes, there. Over there, too... Good.","TWN":"對，還有那裡，跟這裡…沒錯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…음?","JPN":"……ん？","ENG":"Mm?","TWN":"…嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_02"},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"왜 그러세요?","JPN":"どうしました？","ENG":"What’s wrong?","TWN":"怎麼了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아니, 아무것도 아니야.","JPN":"ううん、何でもないわ。","ENG":"Ah, nothing.","TWN":"沒事，沒什麼。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"미안하지만 계약서는 나중에 쓰자. 정직원이 되기 전에, 니콜 양이 이 일에 적성에 맞는지 먼저 확인해보는 거야.","JPN":"悪いけど、契約書は後にしましょう。正式に働く前に、\\nニコルちゃんが本当にこの仕事に適性があるか、まずは試してみないと。","ENG":"I'm sorry, but let's sign your contract later. Before I hire you as a regular employee, I want to make sure you really like being a bartender.","TWN":"不好意思，合約等之後再完成吧。在你正式成為員工之前，我想先確認一下你是否適合這份工作。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"열심히 할게요! 일은 당장이라도 시작할 수 있어요!","JPN":"一生懸命頑張ります！　仕事は今すぐにでも始められます！","ENG":"I'll work hard! I can start right now if you want!","TWN":"我會努力的！我可以立刻上工！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗. 의욕이 넘쳐서 좋네.","JPN":"フフッ、やる気満々でいいわね。","ENG":"Hah hah. You're so enthusiastic, aren't you?","TWN":"呵呵，非常好，這麼有拚勁！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(괜한 걱정을 했네요. 가게 주인 분이 그렇게 까다로운 사람은 아니라 다행이에요.)","JPN":"(余計な心配でした。店主の方がそんなに気難しい方ではなさそうでよかったです。)","ENG":"(I worried for nothing. I'm glad my boss isn't a difficult person.)","TWN":"(根本是白擔心的嘛 ～幸好這家店的老闆娘不是難搞的人！)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(위장은 성공적인 것 같으니, 이제 악마를 찾기만 하면 되겠어요!)","JPN":"(潜入には成功したみたいですし、あとは悪魔を探すだけ！)","ENG":"(Now that I've successfully infiltrated the place, I just need to find the devil!)","TWN":"(看來我的偽裝很成功，接下來就專心揪出魔鬼吧！)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 일을 시작하기 전에 먼저 우리 가게에서 일하는 법을 배워야겠지?","JPN":"でも仕事を始める前に、まずはうちの店のやり方を覚えてもらわないとね？","ENG":"But before you start, you need to learn a few things about this bar.","TWN":"不過在開始上班前，要先知道一下我們店裡的規矩吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"우리 꼬마 임금님이 가르쳐 줄 테니 잘 배워 보도록 해.","JPN":"うちの小さな王様が教えてくれるから、よく聞いて覚えるようにね。","ENG":"Little majesty here will teach them to you.","TWN":"小不點國王會教你，你要好好學。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"꼬마 임금님이요?","JPN":"小さな王様ですか？","ENG":"Little majesty?","TWN":"小不點國王？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"자, 잘 왔다, 신입. 지금부터 교육을 시작하도록 하마.","JPN":"よ、よくぞ来た、新人。これより教育を始めるとしよう。","ENG":"W-welcome, recruit. Let's start your training.","TWN":"歡…迎你，菜鳥。現在開始員工教育訓練。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아… 네! 잘 부탁드려요!","JPN":"あっ……はい！　よろしくお願いします！","ENG":"Ah... Okay! Thank you!","TWN":"喔…好！請多指教！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(좀 전에 봤던 악마가 여기 있는데요? 역시 꿈이 아니었어요.)","JPN":"(さっき見た悪魔がここにいます。やっぱり夢ではありませんでした！)","ENG":"(Here's the devil I saw earlier. It wasn't a dream at all.)","TWN":"(剛才看到的魔鬼原來在這裡？我果然不是在作夢！)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(아니, 하지만 그렇다고 하기엔 절 못 알아보는 것 같은데요?)","JPN":"(いえ、でもそのはずなのに私のことを覚えていないようですね？)","ENG":"(But wait, I don't think she remembers me.)","TWN":"(等等，但她似乎不認得我？)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(이번엔 신중해지는 편이 좋겠어요. 어쩌면 진짜 뿔이 아닐 수도 있고…)","JPN":"(今度は慎重になったほうがよさそうです。\\nもしかしたら本物の角ではない可能性もありますし……)","ENG":"(I'd better be careful this time. It's possible they're not real horns...)","TWN":"(這次還是別太衝動，說不定那不是真的角…)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(아닐 수도…)","JPN":"(違うかも……)","ENG":"(They are not real...)","TWN":"(說不定…)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"으아아앗, 잠깐! 부러져! 그렇게 당기면 부러진다고!","JPN":"ふえええ、ちょっと待って！　折れちゃう！　そんなに引っ張ったら折れちゃうよお！","ENG":"Ow, ow! Hey, stop pulling on my horns! You're going to break them!","TWN":"哎唷，放手啦！你幹嘛！這樣拉會斷掉啦！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗?! 죄송해요! 좀처럼 보기 어려운 거라 무심코 그만…!","JPN":"あっ！？　すみません！　とても珍しくてつい……！","ENG":"Ah? I'm sorry! I just... I've never seen anything like them...","TWN":"喔？！抱歉！覺得有點稀奇，不知不覺就…！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그런데 그 뿔, 머리띠 장식이 아니네요.","JPN":"この角、カチューシャとかではないんですね。","ENG":"But your horns, they're not decorations.","TWN":"不過我還以為那個角是頭飾，原來不是喔？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"그야 당연하지! 이 뿔은 마왕의 상징이다!","JPN":"それは当然だ！　この角は魔王の象徴！","ENG":"Of course not! They're the symbol of the Demon Lord!","TWN":"當然不是！這可是魔王的標誌！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"마왕……?","JPN":"魔王……？","ENG":"Demon... Lord?","TWN":"魔王……？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그게 뭐죠? 악마랑 다른 건가요?","JPN":"それってなんですか？　悪魔とは違うものですか？","ENG":"What's that? Is it different from normal devils?","TWN":"那是什麼？和魔鬼不一樣嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"무엄하구나! 감히 마왕을 악마와 같은 취급 하다니!","JPN":"無礼者め！　魔王と悪魔を同じ扱いにするとは！","ENG":"How dare you? We Demon Lords are totally different from lowly devils!","TWN":"大膽！竟然將魔王和魔鬼相提並論！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"딸꾹…","JPN":"……ひっく。","ENG":"*Hiccups!*","TWN":"嗝…"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"으음…","JPN":"ううん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_QM","text":{"KOREA":"이 몸은 위대한 마왕 모르가나 모드렛이다!","JPN":"吾輩は偉大なる魔王、モルガナ・モードレッドである！","ENG":"I'm the great Demon Lord, Morgana Mordred!","TWN":"本王可是偉大的魔王 莫甘娜 莫德雷！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모?","JPN":"モモ？","ENG":"So, Momo.","TWN":"莫莫？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_QM","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"멋대로 줄여서 부르지 마!","JPN":"勝手に略して呼ぶな！","ENG":"Don't shorten my name like that!","TWN":"不要隨便把人家的名字縮寫好嗎！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸의 이름은 울던 아기도 뚝 그치게 만드는 무시무시한 이름이니라!","JPN":"吾輩の尊名は泣く子も黙る恐ろしい名前である！","ENG":"My name alone can make babies stop crying, because I'm so terrifying!","TWN":"本王的名字可是可怕到，能讓哭泣中的嬰兒立刻閉嘴呢！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"베이비시터라니. 어린 나이에 기특하네요.","JPN":"ベビーシッターの仕事もしているんですか？　まだ幼いのに偉いですね。","ENG":"Oh, you babysit? That's not an easy job for a young girl like you.","TWN":"原來你是保母？年紀輕輕就當保母，很少見呢！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"베이비시터가 아냐!","JPN":"ベビーシッターじゃない！","ENG":"I'm not a babysitter!","TWN":"我才不是保母咧！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그리고 어리지 않아! 난 나이가 아주 많다고!","JPN":"そして幼くなぞない！　吾輩はかなり年を取っているのだ！","ENG":"And also, I'm not young! I'm very old, you know!","TWN":"而且我一點也不小！我年紀超大的！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모는 몇 살?","JPN":"モモはいくつなんですか？","ENG":"How old are you, Momo?","TWN":"莫莫你幾歲？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은… 3만 살이니라!","JPN":"吾輩は……3万歳である！","ENG":"I am... thirty thousand years old!","TWN":"本王…三萬歲！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에에?!","JPN":"えええっ！?","ENG":"Say what?","TWN":"什麼？！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(속을 뻔했어요. 자그마치 3만 살이라니… 평범한 인간은 아니네요.)","JPN":"(あやうく騙されるところでした。なんと3万歳だなんて……\\n普通の人間ではありませんね。)","ENG":"(She almost had me fooled. Thirty thousand years old? I knew she wasn't an ordinary human!)","TWN":"(差點被她的外表給欺騙，竟然已經三萬歲…果然不是普通人！)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(귀여운 어린아이 모습으로 절 방심시키다니 간사하군요. 악마답다고 해야 할까요.)","JPN":"(かわいい子供の姿で私を油断させるなんてずる賢いですね。悪魔らしいというべきでしょうか。)","ENG":"(Such a cunning devil, using its innocent childlike appearance to make me lower my guard.)","TWN":"(是想用可愛的外表讓我卸下心防嗎？真是奸詐！這是魔鬼會用的招數嗎？)"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"뭐, 뭐냐. 그렇게 노려보다니.","JPN":"な、なんだ。なにをそんなにジロジロ見ている。","ENG":"W-what? Why are you glaring at me like that?","TWN":"你…你幹嘛，幹嘛一直盯著我看？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 죄송해요. 잠시 다른 생각을 하느라.","JPN":"あっ、すみません。ちょっと他のことを考えちゃって。","ENG":"Oh, sorry. I was distracted for a moment.","TWN":"喔，不好意思，我剛在想其他事。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그러면 뭐부터 시작하면 좋을까요? 화장실 청소?","JPN":"それでは何から始めればいいでしょう？　トイレ掃除？","ENG":"Okay, what do you want me to do? Clean the restrooms?","TWN":"那要怎麼開始呢？先打掃廁所嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아니면 레몬 썰기?","JPN":"それともレモン切り？","ENG":"Or slice some lemons?","TWN":"還是切檸檬？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L36_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"흐엑…! 해, 해치지 마세요!","JPN":"ひいっ……！　い、いじめないでください！","ENG":"Heek! P-please don't hurt me!","TWN":"嗚…！別…別殺我！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"蛤？"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"아, 아니… 음료 만드는 법부터 해치울 거라고 말했을 뿐이다.","JPN":"あ、いや……ソフトドリンク作りからやると言おうとしただけだ。","ENG":"A-hem... I said you should make some drinks first.","TWN":"喔，沒事…我說別在那邊殺時間，先學怎麼調製飲料吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그래도 괜찮은 건가요? 신입 바텐더는 허드렛일부터 시작하는 줄 알았는데요.","JPN":"いいんですか？　新人バーテンダーは雑務から始まるのだと思っていました。","ENG":"Are you sure? I thought new bartenders were supposed to do chores in the beginning.","TWN":"這樣沒關係嗎？我以為菜鳥調酒師都是從打雜開始的。"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"수, 순서는 내 마음이야! 그러니까 칼부터 내려놔!","JPN":"じゅ、順番は吾輩が決めるのだ！　だからその包丁はしまっておけ！","ENG":"I-I get to decide that! So, put down your knife!","TWN":"呃…我叫你學什麼你就學什麼！先把刀放下吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"UI_BASE_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};